import React from "react";
function Footer() {
  return (
    <div className="container">
      <div className="row">
        <div className="col-3">
          <img src="media/images/logo.svg" style={{ width: "50%" }}></img>
          <p className='p-2'>© 2010 - 2026, Zerodha Broking Ltd. All rights reserved.</p>
        </div>
        <div className="col-3 p-2"><p>Account</p></div>
        <div className="col-3"><p>Support</p></div>
        <div className="col-3"><p>Company</p></div>
      </div>
    </div>
  );
}

export default Footer;
